const launch = $('Get Pre-Launch Launches').item.json;
const signals = $('Fetch Recent Signals').all().map(i => i.json);

const daysUntil = launch.days_until_launch;
const signalCount = signals.length;

// Build signal summary grouped by type
const byType = {};
for (const s of signals) {
  if (!byType[s.signal_type]) byType[s.signal_type] = [];
  byType[s.signal_type].push({ title: s.title, company: s.company_name, summary: (s.summary || '').substring(0, 200) });
}

// Compute readiness scores
const messagingCount = (byType['messaging'] || []).length;
const positioningCount = (byType['positioning'] || []).length;
const pricingCount = (byType['pricing'] || []).length;
const proofCount = (byType['proof'] || []).length;

const competitorLandscape = Math.min(100, 40 + signalCount * 4);
const messagingReadiness = Math.min(100, 30 + messagingCount * 15);
const marketTiming = daysUntil > 14 ? 80 : daysUntil > 7 ? 60 : daysUntil > 3 ? 40 : 20;
const objectionCoverage = Math.min(100, 20 + proofCount * 10 + pricingCount * 10);
const battlecardFreshness = Math.min(100, 30 + signalCount * 5);

const overallScore = Math.round(
  (competitorLandscape + messagingReadiness + marketTiming + objectionCoverage + battlecardFreshness) / 5
);

// Build risk factors
const risks = [];
if (messagingReadiness < 50) risks.push({ label: 'Messaging Gap', detail: 'Few competitor messaging signals detected. Update battlecards before launch.', severity: 'high' });
if (daysUntil <= 3) risks.push({ label: 'Tight Timeline', detail: `Only ${daysUntil} days until launch. Limited time for adjustments.`, severity: 'high' });
if (objectionCoverage < 40) risks.push({ label: 'Objection Coverage', detail: 'Low objection readiness. Review competitive proof points.', severity: 'medium' });

// Build opportunities
const opportunities = [];
if (pricingCount > 0) opportunities.push({ label: 'Pricing Intel', detail: `${pricingCount} pricing signals detected. Check for advantageous positioning.` });
if (positioningCount > 0) opportunities.push({ label: 'Positioning Shifts', detail: `${positioningCount} positioning changes detected. May create opening.` });

// Build brief content
const briefTitle = `Intelligence Brief — T-${daysUntil}d`;
const sections = Object.entries(byType).map(([type, sigs]) => {
  return `## ${type.charAt(0).toUpperCase() + type.slice(1)} Signals (${sigs.length})\n` +
    sigs.map(s => `- **${s.company}**: ${s.title}`).join('\n');
}).join('\n\n');

const briefMd = `# ${briefTitle}\n**Launch:** ${launch.launch_name} | **Product:** ${launch.product_name}\n**Days to Launch:** ${daysUntil} | **Readiness:** ${overallScore}/100\n\n---\n\n${sections}\n\n---\n\n### Risk Factors\n${risks.map(r => `- **[${r.severity.toUpperCase()}]** ${r.label}: ${r.detail}`).join('\n') || 'None identified'}\n\n### Opportunities\n${opportunities.map(o => `- ${o.label}: ${o.detail}`).join('\n') || 'None identified'}`;

return [{
  json: {
    launch_id: launch.launch_id,
    user_id: launch.user_id,
    days_until_launch: daysUntil,
    brief_title: briefTitle,
    brief_md: briefMd,
    brief_json: JSON.stringify({ signal_summary: byType, risks, opportunities }),
    signal_count: signalCount,
    overall_score: overallScore,
    competitor_landscape: competitorLandscape,
    messaging_readiness: messagingReadiness,
    market_timing: marketTiming,
    objection_coverage: objectionCoverage,
    battlecard_freshness: battlecardFreshness,
    risks_json: JSON.stringify(risks),
    opportunities_json: JSON.stringify(opportunities),
    recommendations_json: JSON.stringify(risks.map(r => ({ label: r.label, detail: r.detail, priority: r.severity })))
  }
}];
